-- Cancel Keith + Madison sessions from today on
UPDATE tutorSessions SET status='cancelled', sessionNotes=CONCAT(IFNULL(sessionNotes,''),' | 2026-05-20 audit: tutor deactivated.') WHERE tutorId IN (510001, 510002) AND scheduledAt >= '2026-05-20 00:00:00' AND status='scheduled';

-- Cancel all sessions after Sophie's last day (Tue May 26)
UPDATE tutorSessions SET status='cancelled', sessionNotes=CONCAT(IFNULL(sessionNotes,''),' | 2026-05-20 audit: no tutors after May 26 — Mom + Grandma run school.') WHERE scheduledAt > '2026-05-26 23:59:59' AND status='scheduled';

-- Verify what's left
SELECT ts.id, t.name, DATE(ts.scheduledAt) AS dt, ts.status, ts.durationMin FROM tutorSessions ts LEFT JOIN tutors t ON t.id=ts.tutorId WHERE ts.scheduledAt >= '2026-05-20 00:00:00' AND ts.status='scheduled' ORDER BY ts.scheduledAt;

